on_write:
let res = #{ action: "Allow" };
if !payload.contains("column_family") {
    res.action = "Reject";
    res.reason = "Missing column_family definition";
}
res

on_read:
let res = #{ payload: payload };
if payload.column_family == "system_events" {
    res.match_found = true;
} else {
    res.match_found = false;
}
res

on_index:
let res = #{ score: 1.0 };
if payload.contains("ttl") {
    res.ttl = payload.ttl;
}
res
